 9	 * DOM. A `RichText` value is a CLOSED token model (text / bold / italic / link) —
10	 * never arbitrary HTML — so this renderer is the only place page copy becomes markup,
11	 * and every link `href` already crossed the `ExternalHttpsUrl` / `MailtoHref`
12	 * brand on decode (`make-impossible-states-unrepresentable`, `boundary-discipline`).
13	 *
14	 * Paragraph breaks: the legacy flat-key copy used literal `<br/><br/>` between
15	 * paragraphs (e.g. the FAQ answers). That carries through the token model as a
16	 * `\n\n` inside a `text` / `bold` run; `renderText` turns each `\n\n` back into a
17	 * `<br/><br/>` pair so the rendered output is identical to the pre-migration
18	 * routes (`derive-dont-sync` — the break is data in the copy, not re-encoded JSX).
19	 */
20	
21	const renderText = (value: string): React.ReactNode =>
22	  value.split('\n\n').map((part, index, parts) => (
23	    <React.Fragment key={index}>
24	      {part}
25	      {index < parts.length - 1 ? (
26	        <>
27	          <br />
28	          <br />
29	        </>
30	      ) : null}
31	    </React.Fragment>
32	  ));
33	
34	export function RichText({ runs }: { runs: readonly RichTextRun[] }) {
35	  return (
36	    <>
37	      {runs.map((run, index) => {
38	        switch (run.kind) {
39	          case 'text':
40	            return (
41	              <React.Fragment key={index}>
42	                {renderText(run.value)}
43	              </React.Fragment>
44	            );
45	          case 'bold':
46	            return (
47	              <span className="font-bold" key={index}>
48	                {renderText(run.value)}
49	              </span>
50	            );
51	          case 'italic':
52	            return (
53	              <span className="italic" key={index}>
54	                {renderText(run.value)}
55	              </span>
56	            );
57	          case 'link':
58	            return (
59	              <ExternalLink href={run.href} key={index}>
60	                {run.text}
61	              </ExternalLink>
62	            );
63	        }
64	      })}
65	    </>
66	  );
