566	     * EVERY failure mode (absent / unreachable / malformed). The fallback is
567	     * scoped to this one object, so a corrupt `faq.json` cannot break `about` or
568	     * the conference read — the blast-radius isolation is structural, one cache
569	     * per object. The TTL + single-flight + manual-invalidate semantics are the
570	     * site cache's, applied per object (`use-the-platform`).
571	     */
572	    const makeObjectCache = (
573	      key: string,
574	      spec: ObjectSpec<unknown, unknown>,
575	    ): Effect.Effect<ObjectCache> =>
576	      Effect.gen(function* () {
577	        const decode = Schema.decodeUnknownEffect(spec.schema);
578	        const fetch: Effect.Effect<unknown> = Effect.gen(function* () {
579	          const object = yield* storage.get(key);
580	          const json = yield* Effect.promise(() =>
581	            new Response(object.stream).text(),
582	          );
583	          const parsed = yield* parseJson(json);
584	          return yield* decode(parsed);
585	        }).pipe(
586	          Effect.catchCause((cause) =>
587	            Effect.logWarning(`Content: could not read ${key}`, cause).pipe(
588	              Effect.as(spec.default),
589	            ),
590	          ),
591	        );
592	        const [read, invalidate] = yield* Effect.cachedInvalidateWithTTL(
593	          fetch,
594	          Duration.millis(CACHE_TTL_MS),
595	        );
596	        return { read, invalidate };
597	      });
