600	    // sets are closed and small — 7 pages + 3 forms). Eager construction keeps
601	    // each `getPage` / `getForm` a pure cache read with no first-call lock, and
602	    // the bust dispatch a direct record lookup over the closed id.
603	    const pageCaches = {} as Record<PageId, ObjectCache>;
604	    for (const page of PAGE_IDS) {
605	      pageCaches[page] = yield* makeObjectCache(
606	        pageObjectKey(page),
