569	        // user error, so it dies rather than masquerading as an `IssueError`.
570	        const json = yield* codec.encodeDraftJson(decoded).pipe(Effect.orDie);
571	        yield* storage.put(codec.keys.draftKey, json, 'application/json').pipe(
572	          Effect.mapError(
