574	              new IssueError({
575	                message: `Saving the draft failed — is the bucket configured? ${String(cause)}`,
576	                issues: [],
577	                status: 502,
578	              }),
579	          ),
580	        );
581	        return yield* codec.encodeObject(decoded).pipe(Effect.orDie);
582	      });
