584	    /** Encode the scope's current document to its canonical mergeable JSON. */
585	    const encodedCurrent = (
586	      codec: ScopeCodec,
587	      scope: ContentScope,
588	    ): Effect.Effect<Json> =>
589	      Effect.gen(function* () {
590	        const { content: current } = yield* loadInternal(scope);
591	        return yield* codec.encodeObject(current).pipe(Effect.orDie);
592	      });
593	
594	    const editDocument = Effect.fn('DraftEditor.editDocument')(function* <
595	      S extends ContentScope,
596	    >(scope: S, override: Json) {
597	      const codec = resolveScope(scope);
598	      const base = yield* encodedCurrent(codec, scope);
599	      const merged = deepMerge(base, override);
600	      const decoded = yield* decodeOrReject(codec, merged);
601	      return (yield* storeDraft(codec, decoded)) as ScopeEncoded<S>;
602	    });
603	
604	    const applyImageUpload = Effect.fn('DraftEditor.applyImageUpload')(
605	      function* <S extends ContentScope>(
606	        scope: S,
607	        targetPath: string,
608	        key: AssetKey,
609	      ) {
610	        const codec = resolveScope(scope);
611	        const encoded = yield* encodedCurrent(codec, scope);
612	        const next = setAtPath(encoded, targetPath, key);
613	        const decoded = yield* decodeOrReject(codec, next);
614	        return (yield* storeDraft(codec, decoded)) as ScopeEncoded<S>;
615	      },
