618	    const applyListOps = Effect.fn('DraftEditor.applyListOps')(function* <
619	      S extends ContentScope,
620	    >(scope: S, ops: readonly ListOp[]) {
621	      const codec = resolveScope(scope);
622	      const encoded = yield* encodedCurrent(codec, scope);
