631	    const publish = Effect.fn('DraftEditor.publish')(function* (
632	      scope: ContentScope,
633	    ) {
634	      const codec = resolveScope(scope);
635	      const { draftKey, publishedKey } = codec.keys;
636	      // Promote the just-saved edit. A pending draft is ALWAYS the publish
637	      // source — it is what the admin just edited and saved, so it is published
638	      // directly and never re-reconciled against the published document by
639	      // `lastModified`. This is the behaviour the old inline path had (it wrote
640	      // the freshly-merged document straight to the published key) and is the
641	      // reason `publish` must NOT route through `load`: `load`'s strict
642	      // `draftHead > publishedHead` reconciliation is for *editor-open* only, and
643	      // on a second-granular backend (S3/MinIO) a draft saved and published
644	      // within the same second compares EQUAL — routing publish through `load`
645	      // would silently re-publish the stale document and then delete the edit.
646	      // With no draft, the already-live document is re-published.
647	      const draft = yield* readDocument(codec, draftKey);
648	      const published = yield* readDocument(codec, publishedKey);
649	      const source = Option.isSome(draft)
650	        ? draft.value
651	        : Option.isSome(published)
