659	      // *absence* (an empty list), never a tolerance for half-filled content
660	      // (ADR 0006, CONTEXT §Section skip). Only after this gate passes does the
661	      // published object get written.
662	      const draftJson = yield* codec.encodeDraftJson(source).pipe(Effect.orDie);
663	      const strict = yield* parseJson(draftJson).pipe(
664	        Effect.flatMap(codec.decodePublish),
665	        Effect.mapError(
666	          (error) =>
667	            new IssueError({
668	              message:
669	                'Cannot publish — finish the fields below (added or empty items must be complete) and resubmit.',
670	              issues: issueMessages(error.issue),
671	              status: 400,
672	            }),
673	        ),
674	      );
675	      const json = yield* codec.encodePublishJson(strict).pipe(Effect.orDie);
676	      yield* storage.put(publishedKey, json, 'application/json').pipe(
677	        Effect.mapError(
678	          (cause) =>
679	            new IssueError({
680	              message: `Publishing failed — is the bucket configured? ${String(cause)}`,
681	              issues: [],
682	              status: 502,
683	            }),
684	        ),
685	      );
686	      // Best-effort cleanup so the bucket stays tidy. Correctness does NOT
687	      // depend on it: the published document above already carries the promoted
688	      // draft, so a leftover draft (from a failed delete) only governs what the
689	      // *editor* reopens, where `load`'s strictly-newer reconciliation keeps it
690	      // from reopening as stale content. Hence it must not fail the publish —
691	      // the live document is already written.
692	      yield* storage.delete(draftKey).pipe(Effect.ignore);
