694	      // makes that page live on the next read without busting any other page,
695	      // form, or the conference (`site`) cache.
696	      yield* content.bust(bustTargetOf(scope));
697	    });
698	
699	    return Service.of({
700	      load,
701	      editDocument,
702	      applyImageUpload,
703	      applyListOps,
704	      publish,
705	    });
706	  }),
707	);

