227	/**
228	 * The per-item structural controls (ADR 0006): move up / down (a reorder
229	 * submitting the full new id order so a partial/stale order never drops an item)
230	 * and remove. The `ids` is the list's current id order so a move computes the
231	 * swapped permutation client-side.
232	 */
233	export function ItemControls({
234	  listPath,
235	  ids,
236	  index,
237	}: {
238	  readonly listPath: string;
239	  readonly ids: readonly string[];
240	  readonly index: number;
241	}) {
242	  const id = ids[index];
243	  if (id === undefined) return null;
244	  // Swap two positions to compute the reorder permutation, guarding the bounds so
245	  // the disabled edge buttons never index past the array; out of range, the order
246	  // is returned unchanged.
247	  const swapped = (a: number, b: number): string => {
248	    const aId = ids[a];
249	    const bId = ids[b];
250	    if (aId === undefined || bId === undefined) return ids.join(',');
251	    const next = [...ids];
252	    next[a] = bId;
253	    next[b] = aId;
254	    return next.join(',');
255	  };
256	  return (
257	    <div className="flex items-center gap-1">
258	      <ListOpButton
259	        listPath={listPath}
260	        kind="reorder"
261	        value={index > 0 ? swapped(index, index - 1) : ids.join(',')}
262	        label="↑"
263	        disabled={index === 0}
264	      />
265	      <ListOpButton
266	        listPath={listPath}
267	        kind="reorder"
268	        value={index < ids.length - 1 ? swapped(index, index + 1) : ids.join(',')}
269	        label="↓"
270	        disabled={index === ids.length - 1}
271	      />
272	      <ListOpButton
273	        listPath={listPath}
274	        kind="remove"
275	        value={id}
276	        label="Remove"
277	        variant="danger"
278	      />
279	    </div>
280	  );
281	}
