 28	const isPlainObject = (value: Json): value is { readonly [k: string]: Json } =>
 29	  typeof value === 'object' && value !== null && !Array.isArray(value);
 30	
 31	/**
 32	 * A dotted path to a list (array) inside the encoded document — e.g. `team`, or
 33	 * `conferences./2024.speakers`. A segment that descends THROUGH an array selects
 34	 * the item by its **identity** (a conference's `slug`, a list item's `id` — ADR
 35	 * 0006), never by position; string segments key into an object. The path
 36	 * addresses the **array**, not an item; the item to add / remove / reorder is
 37	 * addressed by its `id` inside the `ListOp`.
 38	 */
 39	export type ListPath = string;
 40	
 41	/**
 42	 * A single structural list edit, addressed by item id (ADR 0006). Exactly one of
 43	 * add / remove / reorder per op so an op can never be two things at once
 44	 * (`make-impossible-states-unrepresentable`):
 45	 *   - `add`    — append a fresh item `{ id }` (empty otherwise) to the list. Its
 46	 *                required fields are absent, so it is publish-invalid until edited
 47	 *                (ADR 0006 consequence) — the id exists server-side so a later
 48	 *                photo upload / field edit has a target.
 49	 *   - `remove` — drop the item whose `id` matches; a no-op if absent.
 50	 *   - `reorder`— reorder the list to the given `ids` permutation; ids not present
 51	 *                are ignored and present-but-unnamed ids keep their relative order
 52	 *                after the named ones (so a partial order never drops an item).
 53	 */
 54	export type ListOp =
 55	  | { readonly add: { readonly listPath: ListPath; readonly id: ListItemId } }
 56	  | { readonly remove: { readonly listPath: ListPath; readonly id: ListItemId } }
 57	  | {
 58	      readonly reorder: {
 59	        readonly listPath: ListPath;
 60	        readonly ids: readonly ListItemId[];
 61	      };
 62	    };
 63	
 64	export const addOp = (listPath: ListPath, id: ListItemId): ListOp => ({
 65	  add: { listPath, id },
 66	});
 67	
 68	export const removeOp = (listPath: ListPath, id: ListItemId): ListOp => ({
 69	  remove: { listPath, id },
 70	});
 71	
 72	export const reorderOp = (
 73	  listPath: ListPath,
 74	  ids: readonly ListItemId[],
 75	): ListOp => ({ reorder: { listPath, ids } });
 76	
 77	/** The `id` of a list item, or `undefined` when the item is not an id-bearing object. */
 78	const itemId = (item: Json): string | undefined =>
 79	  isPlainObject(item) && typeof item['id'] === 'string' ? item['id'] : undefined;
 80	
 81	/**
 82	 * The stable identity a *path segment* matches an array item by (ADR 0006): a
 83	 * list item's `id`, or a conference's `slug`. Used to navigate THROUGH an array
 84	 * (e.g. `conferences./2024.speakers`) to a nested list — positional indexing is
 85	 * gone, so a reordered `conferences` array still resolves the right year.
 86	 */
 87	const navIdentity = (item: Json): string | undefined => {
 88	  if (!isPlainObject(item)) return undefined;
 89	  if (typeof item['id'] === 'string') return item['id'];
 90	  if (typeof item['slug'] === 'string') return item['slug'];
 91	  return undefined;
 92	};
 93	
 94	/**
 95	 * Apply one op to the array `list`, returning a fresh array (never mutating). The
 96	 * op kinds are exhaustive over the `ListOp` union, so adding a kind without
 97	 * handling it is a type error (`make-impossible-states-unrepresentable`).
 98	 */
 99	const applyOp = (list: readonly Json[], op: ListOp): readonly Json[] => {
100	  if ('add' in op) {
101	    // Appending a duplicate id would make two items share an identity, which the
102	    // id-keyed merge could no longer distinguish — guard it (the caller mints a
103	    // fresh id, so this only fires on a malformed resubmission).
104	    if (list.some((item) => itemId(item) === op.add.id)) return list;
105	    return [...list, { id: op.add.id }];
106	  }
107	  if ('remove' in op) {
108	    return list.filter((item) => itemId(item) !== op.remove.id);
109	  }
110	  // reorder: place the named ids first in their given order, then append any
111	  // surviving item the order omitted (in its original relative order) so a
112	  // partial / stale order can never silently drop an item.
113	  const named = new Map(
114	    list.flatMap((item) => {
115	      const id = itemId(item);
116	      return id === undefined ? [] : ([[id, item]] as const);
117	    }),
118	  );
119	  const ordered: Json[] = [];
120	  const placed = new Set<string>();
121	  for (const id of op.reorder.ids) {
122	    const item = named.get(id);
123	    if (item !== undefined && !placed.has(id)) {
124	      ordered.push(item);
125	      placed.add(id);
126	    }
127	  }
128	  for (const item of list) {
129	    const id = itemId(item);
130	    if (id === undefined || !placed.has(id)) ordered.push(item);
131	  }
132	  return ordered;
133	};
134	
135	/**
136	 * Navigate to the array at `path` inside `root`, replace it via `update`, and
137	 * return a fresh document. When the path descends THROUGH an array (e.g.
138	 * `conferences./2024.speakers`), the next segment selects the array item by its
139	 * **identity** (`slug` / `id`), never by position (ADR 0006, sub-commit 2.4) — so
140	 * a reordered `conferences` still resolves the right year. Intermediate
141	 * containers are cloned along the path so the input is never mutated; a path that
142	 * does not resolve to an array (an unknown identity, a malformed control field)
143	 * is left untouched — the strict decode downstream is the gate.
144	 */
145	const updateListAtPath = (
146	  root: Json,
147	  path: readonly string[],
148	  update: (list: readonly Json[]) => readonly Json[],
149	): Json => {
150	  const [head, ...rest] = path;
151	  if (head === undefined) {
152	    return Array.isArray(root) ? update(root) : root;
153	  }
154	  if (Array.isArray(root)) {
155	    const index = root.findIndex((item) => navIdentity(item) === head);
156	    if (index < 0) return root;
157	    const next = [...root];
158	    next[index] = updateListAtPath(root[index] as Json, rest, update);
159	    return next;
160	  }
161	  if (isPlainObject(root)) {
162	    if (!(head in root)) return root;
163	    return { ...root, [head]: updateListAtPath(root[head] as Json, rest, update) };
164	  }
165	  return root;
166	};
167	
168	/**
169	 * Apply a sequence of id-keyed list ops to the encoded document, returning a new
170	 * document (the input is never mutated — `boundary-discipline`). Ops apply in
171	 * order, so a reorder naming a just-added id sees it. A `listPath` that does not
172	 * resolve to an array is skipped; the merged result is Schema-decoded downstream,
173	 * the single boundary where an invalid edit (an empty appended item on publish)
174	 * is rejected.
175	 */
176	export const applyListEdit = (base: Json, ops: readonly ListOp[]): Json =>
177	  ops.reduce((doc, op) => {
178	    const listPath =
179	      'add' in op
180	        ? op.add.listPath
181	        : 'remove' in op
182	          ? op.remove.listPath
183	          : op.reorder.listPath;
184	    return updateListAtPath(doc, listPath.split('.'), (list) => applyOp(list, op));
185	  }, base);
186	
187	// ---------------------------------------------------------------------------
188	// Control-field convention (admin view ⇄ action)
189	// ---------------------------------------------------------------------------
190	
191	/**
192	 * The form field-name prefix marking a list-op control field. The view's per-list
193	 * Add / Remove / reorder controls submit `list:<listPath>:<kind>` so the action
194	 * can recover the ops with `collectListOps`. The prefix keeps these control
195	 * fields out of `assembleOverrides`' dotted-path namespace (which never starts
196	 * with `list:`), so the two parsers can read the same `FormData` without overlap.
197	 */
198	const LIST_OP_PREFIX = 'list:';
199	
200	export type ListOpKind = 'add' | 'remove' | 'reorder';
201	
202	export const listOpFieldName = (
203	  listPath: ListPath,
204	  kind: ListOpKind,
205	): string => `${LIST_OP_PREFIX}${listPath}:${kind}`;
206	
207	/**
208	 * Parse the `list:<listPath>:<kind>` control fields of a submitted form into the
209	 * ordered op list. `add`/`remove` carry the target id as the value; `reorder`
210	 * carries the surviving ids comma-joined. Ids are kept as raw strings here
211	 * (parsed from untrusted form input) and branded only where `applyListEdit`
212	 * threads them back into the document the decoder validates — this helper does
213	 * not invent a brand at a non-boundary (`boundary-discipline`). A control field
214	 * with an empty / malformed value is skipped rather than throwing.
215	 */
216	export const collectListOps = (
217	  entries: Iterable<readonly [string, FormDataEntryValue]>,
218	): readonly ListOp[] => {
219	  const ops: ListOp[] = [];
220	  for (const [name, value] of entries) {
221	    if (typeof value !== 'string' || !name.startsWith(LIST_OP_PREFIX)) continue;
222	    const rest = name.slice(LIST_OP_PREFIX.length);
223	    const sep = rest.lastIndexOf(':');
224	    if (sep === -1) continue;
225	    const listPath = rest.slice(0, sep);
226	    const kind = rest.slice(sep + 1);
227	    if (listPath === '') continue;
228	    if (kind === 'add') {
229	      if (value !== '') ops.push(addOp(listPath, value as ListItemId));
230	    } else if (kind === 'remove') {
231	      if (value !== '') ops.push(removeOp(listPath, value as ListItemId));
232	    } else if (kind === 'reorder') {
233	      const ids = value
234	        .split(',')
235	        .map((id) => id.trim())
236	        .filter((id) => id !== '') as ListItemId[];
237	      if (ids.length > 0) ops.push(reorderOp(listPath, ids));
238	    }
239	  }
240	  return ops;
241	};
242	
243	/**
244	 * The id-keyed form field-name for a leaf of a list item — e.g.
245	 * `fieldName('conferences./2024.speakers', id, 'name.en')` →
246	 * `conferences./2024.speakers.<id>.name.en`. This replaces the positional
247	 * templates (`conferences.0.speakers.1.name.en`) the index merge relied on (ADR
248	 * 0006); the id segment is a validated `ListItemId`, so it can never smuggle a
249	 * `.`-bearing path that would re-split into the wrong shape
250	 * (`boundary-discipline`).
251	 */
252	export const fieldName = (
253	  listPath: ListPath,
254	  id: ListItemId,
255	  leaf: string,
256	): string => `${listPath}.${id}.${leaf}`;

  1	/**
  2	 * Pure helpers for the `/admin` content editor (CMS plan sub-commit C5).
  3	 *
  4	 * The editor edits the one `SiteContent` document. Rather than rebuild the whole
  5	 * (deeply nested, array-bearing) document from scratch on every save — which
  6	 * would make a single typo in one field able to drop an entire speaker bio — the
  7	 * editor takes the **merge-onto-current-document** approach
  8	 * (`make-impossible-states-unrepresentable`, no-bail-outs):
  9	 *
 10	 *   1. the form carries only the fields it renders, named by their dotted JSON
 11	 *      path — list items and conferences keyed by their stable **identity**
 12	 *      (`conferences./2026.themeName.en`, `team.<id>.name`, `translations.fr.…`),
 13	 *      never by array position (ADR 0006);
 14	 *   2. `assembleOverrides` parses those into a nested partial object tree;
 15	 *   3. `deepMerge` overlays that partial onto the *encoded current document*,
 16	 *      reconciling each array by item identity, so every unedited field (long
 17	 *      bios, image keys, `Option` registration windows omitted from the encoded
 18	 *      JSON) survives verbatim and an edit can never land on the wrong item after
 19	 *      a list grew or shrank;
 20	 *   4. the route then Schema-decodes the merged result — the single boundary
 21	 *      where an edit can be rejected (`boundary-discipline`).
 22	 *
 23	 * Keeping this logic pure and separate from the route makes it unit-testable
 24	 * without a runtime (`small-interface-deep-implementation`).
 25	 */
 26	
 27	import { AssetKey } from './schema';
 28	
 29	/**
 30	 * A JSON-shaped value the merge/assemble helpers move around. Arrays / objects
 31	 * are `readonly` so an encoded Effect-Schema value (whose fields are deeply
 32	 * `readonly`) is assignable without a cast; the helpers never mutate their
 33	 * inputs (they build fresh values / clone).
 34	 */
 35	export type Json =
 36	  | string
 37	  | number
 38	  | boolean
 39	  | null
 40	  | readonly Json[]
 41	  | { readonly [key: string]: Json };
 42	
 43	type MutableJsonObject = Record<string, Json>;
 44	
 45	const isPlainObject = (value: Json): value is { readonly [k: string]: Json } =>
 46	  typeof value === 'object' && value !== null && !Array.isArray(value);
 47	
 48	/**
 49	 * The form field-name prefix that marks an image-upload submit. The editor's
 50	 * per-image "Upload" buttons submit `intent=upload:<dotted-key-path>` so the
 51	 * action knows which `…photo.key` / `hero.<crop>.key.<locale>` field to rewrite
 52	 * with the new bucket key once the bytes are stored.
 53	 */
 54	export const IMAGE_UPLOAD_INTENT_PREFIX = 'upload:';
 55	
 56	/**
 57	 * The accepted upload content-types. The resize/WebP pipeline is deferred (CMS
 58	 * plan §"Non-goals"); for now we store the raw bytes under their original
 59	 * content-type, so we only need to gate the obviously-image MIME types to keep
 60	 * a stray PDF / script out of the image namespace.
 61	 */
 62	const ACCEPTED_IMAGE_TYPES = new Set([
 63	  'image/jpeg',
 64	  'image/png',
 65	  'image/webp',
 66	  'image/gif',
 67	  'image/avif',
 68	]);
 69	
 70	export const isAcceptedImageType = (type: string): boolean =>
 71	  ACCEPTED_IMAGE_TYPES.has(type.toLowerCase());
 72	
 73	const EXTENSION_BY_TYPE: Record<string, string> = {
 74	  'image/jpeg': 'jpg',
 75	  'image/png': 'png',
 76	  'image/webp': 'webp',
 77	  'image/gif': 'gif',
 78	  'image/avif': 'avif',
 79	};
 80	
 81	export const extensionForType = (type: string): string =>
 82	  EXTENSION_BY_TYPE[type.toLowerCase()] ?? 'bin';
 83	
 84	/**
 85	 * Recover the dotted key path an image-upload intent targets, or `null` if the
 86	 * intent is not an upload. The path is identity-keyed (ADR 0006), e.g.
 87	 * `upload:conferences./2024.speakers.<id>.photo.key` →
 88	 * `conferences./2024.speakers.<id>.photo.key`.
 89	 */
 90	export const imageUploadTarget = (intent: string): string | null => {
 91	  if (!intent.startsWith(IMAGE_UPLOAD_INTENT_PREFIX)) return null;
 92	  const path = intent.slice(IMAGE_UPLOAD_INTENT_PREFIX.length);
 93	  return path.length > 0 ? path : null;
 94	};
 95	
 96	/**
 97	 * Build a fresh bucket object key for an uploaded image, namespaced under
 98	 * `images/` so it never collides with the bundled `public/<year>/…` art and is
 99	 * obviously an editor upload. `seed` (a millisecond timestamp) keeps successive
100	 * uploads to the same field distinct so a stale cached image is never served
101	 * for a new upload (`make-operations-idempotent` — each upload is its own key).
102	 *
103	 * Returns a branded `AssetKey`, not a raw `string`: the construction
104	 * (`images/uploads/` namespace + a `[a-zA-Z0-9-]` slug) is valid by
105	 * construction, and `AssetKey.make` *validates* that invariant at the producer
106	 * boundary (`boundary-discipline`, `make-impossible-states-unrepresentable`) so
107	 * a non-`AssetKey` can never reach `DraftEditor.applyImageUpload`. A failure
108	 * here would be a slug-construction bug, surfaced as a throw — not a silent
109	 * widening.
110	 */
111	export const uploadedImageKey = (
112	  targetPath: string,
113	  contentType: string,
114	  seed: number,
115	): AssetKey => {
116	  const slug = targetPath.replace(/[^a-zA-Z0-9]+/g, '-').replace(/^-+|-+$/g, '');
117	  return AssetKey.make(
118	    `images/uploads/${slug}-${seed}.${extensionForType(contentType)}`,
119	  );
120	};
