122	/**
123	 * The form-name prefix for a single translation value. Translation keys contain
124	 * dots (`main.newsletter.title`), which collide with the dotted-path convention,
125	 * so translation inputs are named `TRANSLATION_FIELD_PREFIX<locale>:<key>` and
126	 * collected by `collectTranslations` rather than parsed by `assembleOverrides`
127	 * (which skips them). The key is kept whole — never split on its dots.
128	 */
129	export const TRANSLATION_FIELD_PREFIX = 't:';
130	
131	export const translationFieldName = (locale: 'en' | 'fr', key: string): string =>
132	  `${TRANSLATION_FIELD_PREFIX}${locale}:${key}`;
133	
134	const isTranslationField = (name: string): boolean =>
135	  name.startsWith(TRANSLATION_FIELD_PREFIX);
136	
137	/**
138	 * Collect every `t:<locale>:<key>` form field into the bilingual translations
139	 * override, e.g. `t:en:main.newsletter.title` → `{ en: { 'main.newsletter.title':
140	 * '…' } }`. The key keeps its dots verbatim (it is a single map key, not a path).
141	 */
142	export const collectTranslations = (
143	  entries: Iterable<readonly [string, FormDataEntryValue]>,
144	): { readonly en: Record<string, string>; readonly fr: Record<string, string> } => {
145	  const en: Record<string, string> = {};
146	  const fr: Record<string, string> = {};
147	  for (const [name, value] of entries) {
148	    if (typeof value !== 'string' || !isTranslationField(name)) continue;
149	    const rest = name.slice(TRANSLATION_FIELD_PREFIX.length);
150	    const sep = rest.indexOf(':');
151	    if (sep === -1) continue;
152	    const locale = rest.slice(0, sep);
153	    const key = rest.slice(sep + 1);
154	    if (key === '') continue;
155	    if (locale === 'en') en[key] = value;
156	    else if (locale === 'fr') fr[key] = value;
157	  }
158	  return { en, fr };
159	};
