161	/**
162	 * The stable identity of a list / conference item the merge keys on (ADR 0006):
163	 * a list item's `id` (a nanoid), or a conference's `slug` (`/2024`). Both are
164	 * **content** that round-trips through the schema, so an edit addresses an item
165	 * by identity rather than by array position. Returns `undefined` for an item
166	 * that carries neither (the index-keyed merge is gone — an identity-less item is
167	 * never an override target).
168	 */
169	const itemIdentity = (item: Json): string | undefined => {
170	  if (!isPlainObject(item)) return undefined;
171	  if (typeof item['id'] === 'string') return item['id'];
172	  if (typeof item['slug'] === 'string') return item['slug'];
173	  return undefined;
174	};
175	
176	/**
177	 * Set `value` at the dotted `path` inside the fresh override `root`, creating
178	 * intermediate **objects** as needed. The override is a pure nested object tree:
179	 * every array in the document is addressed by item **identity** (ADR 0006), so a
180	 * list-item / conference segment (`/2024`, a nanoid) is an object KEY here, never
181	 * an array index — `setPath` therefore never builds arrays, and the identity
182	 * reconciliation against the base's real arrays happens in `deepMerge`. (The
183	 * index-keyed array construction this used to do is gone — registration-launch
184	 * Branch 2 sub-commit 2.4.)
185	 */
186	const setPath = (root: MutableJsonObject, path: string[], value: Json): void => {
187	  if (path.length === 0) return;
188	  let cursor: MutableJsonObject = root;
189	  for (let i = 0; i < path.length - 1; i += 1) {
190	    const segment = path[i];
191	    if (segment === undefined) return;
192	    const existing: Json | undefined = cursor[segment];
193	    if (existing !== undefined && isPlainObject(existing)) {
194	      cursor = existing as MutableJsonObject;
195	    } else {
196	      const container: MutableJsonObject = {};
197	      cursor[segment] = container;
198	      cursor = container;
199	    }
200	  }
201	  const leaf = path[path.length - 1];
202	  if (leaf === undefined) return;
203	  cursor[leaf] = value;
204	};
