206	/**
207	 * Assemble the nested override object from the editor form. Only entries whose
208	 * name is a dotted path are taken; control fields (`intent`, anything starting
209	 * with `_`) and non-string values (files) are skipped. A leaf named `chapter` /
210	 * `verse` is coerced to a number so the `BibleRef` integer fields decode.
211	 *
212	 * List items and conferences are named by their **identity** segment
213	 * (`team.<id>.name`, `conferences./2024.themeName.en` — ADR 0006), so the
214	 * assembled override is a pure object tree keyed by identity; `deepMerge`
215	 * reconciles it against the base's arrays by matching that identity.
216	 */
217	export const assembleOverrides = (
218	  entries: Iterable<readonly [string, FormDataEntryValue]>,
219	): Json => {
220	  const root: MutableJsonObject = {};
221	  for (const [name, value] of entries) {
222	    if (typeof value !== 'string') continue;
223	    if (name === 'intent' || name.startsWith('_')) continue;
224	    if (isTranslationField(name)) continue;
225	    const path = name.split('.');
226	    const leaf = path[path.length - 1];
227	    const coerced: Json =
228	      (leaf === 'chapter' || leaf === 'verse') && value.trim() !== ''
229	        ? Number(value)
230	        : value;
231	    setPath(root, path, coerced);
232	  }
233	  return root;
234	};
