236	/**
237	 * Rewrite a FAQ-answer override leaf from the editor's plain-text bilingual input
238	 * shape (`{ en, fr }`) into the encoded single-`text`-token `RichText` shape
239	 * (`[{ _tag: 'text', value: { en, fr } }]`) the `FaqPage` schema decodes.
240	 *
241	 * Why this seam (registration-launch Branch 5.5, FAQ add→fill→publish loop): a
242	 * freshly-added FAQ item carries no `answer` (it is `optionalKey` in `DraftFaqPage`,
243	 * absent in `FaqPage` ⇒ publish-invalid). The admin route renders a plain bilingual
244	 * **answer** input for such an item so it CAN be filled, but the form posts it as a
245	 * dotted `items.<id>.answer.en/.fr` pair — a plain `{ en, fr }` object. The encoded
246	 * base `answer` is a `RichText` ARRAY, and `deepMerge`'s identity-keyed array merge
247	 * cannot address an array with an object override (it would silently drop the edit).
248	 * Converting the override leaf to a one-token `RichText` ARRAY makes `deepMerge` fall
249	 * to wholesale array-replacement, so the filled answer lands. The closed token model
250	 * is preserved — the route only edits answers as a single plain `text` run; rich
251	 * (link/bold/italic) answers stay read-only (`boundary-discipline`).
252	 *
253	 * An answer override is emitted ONLY when BOTH locales are non-empty: a single
254	 * `text` token's `value` is the strict both-locales `Text`, so a half-filled
255	 * `{ en: 'x', fr: '' }` would be rejected at DRAFT save — inconsistent with every
256	 * other field, whose empty half is draft-tolerated (ADR 0006). Dropping the
257	 * half-filled answer leaves it ABSENT instead: the draft saves, and publish stays
258	 * blocked until both halves are filled (ADR 0006: incomplete blocks publish, not
259	 * save). This is a pure rewrite of FAQ-answer leaves only; every other override
260	 * passes through untouched.
261	 */
262	export const normalizeFaqAnswers = (override: Json): Json => {
263	  if (!isPlainObject(override)) return override;
264	  const items = override['items'];
265	  if (items === undefined || !isPlainObject(items)) return override;
266	  const rewrittenItems: MutableJsonObject = {};
267	  for (const id of Object.keys(items)) {
268	    const item = items[id];
269	    if (item === undefined || !isPlainObject(item) || !('answer' in item)) {
270	      if (item !== undefined) rewrittenItems[id] = item;
271	      continue;
272	    }
273	    const answer = item['answer'];
274	    const { answer: _drop, ...rest } = item;
275	    if (isPlainObject(answer)) {
276	      const en = answer['en'];
277	      const fr = answer['fr'];
278	      // Emit the token only when both locales are present and non-empty; a
279	      // half-filled answer is dropped so the draft saves and publish stays
280	      // blocked (ADR 0006), never rejected at save by the strict `Text` token.
281	      if (
282	        typeof en === 'string' &&
283	        typeof fr === 'string' &&
284	        en.trim() !== '' &&
285	        fr.trim() !== ''
286	      ) {
287	        rewrittenItems[id] = {
288	          ...rest,
289	          answer: [{ _tag: 'text', value: { en, fr } }],
290	        };
291	        continue;
292	      }
293	    }
294	    rewrittenItems[id] = rest;
295	  }
296	  return { ...override, items: rewrittenItems };
297	};
