299	/**
300	 * Deep-merge `overrides` onto `base`, returning a new value. `base` and
301	 * `overrides` are never mutated.
302	 *
303	 * Objects merge key-by-key. An **array** in `base` is merged by item
304	 * **identity** (ADR 0006), NOT by position: `overrides` for a list arrives as an
305	 * identity-map (`{ <id>: partial }` for `team`/`speakers`, `{ "/2024": partial }`
306	 * for `conferences`), and each override key is matched against the base item
307	 * whose `id` / `slug` equals it — so editing `conferences./2024.themeName.en`
308	 * overlays only that conference's leaf and leaves every other item (and every
309	 * unedited deep field) untouched, even if list positions shifted from an
310	 * add/remove. A base item no override names survives verbatim; an override key
311	 * that matches no base item is ignored (structural add/remove is `applyListEdit`'s
312	 * job, never a field merge's). Every scalar (string / number / boolean / null) is
313	 * replaced.
314	 *
315	 * The old index-aligned array branch is gone (registration-launch Branch 2
316	 * sub-commit 2.4): position is no longer an identity, so an edit can never land
317	 * on the wrong item after a list grew or shrank.
318	 */
319	export const deepMerge = (base: Json, overrides: Json): Json => {
320	  // Identity-keyed merge: an object override onto an array base addresses items
321	  // by `id` / `slug`, never by index.
322	  if (Array.isArray(base) && isPlainObject(overrides)) {
323	    return base.map((item) => {
324	      const identity = itemIdentity(item);
325	      if (identity === undefined) return item;
326	      const next = overrides[identity];
327	      return next === undefined ? item : deepMerge(item, next);
328	    });
329	  }
330	  if (isPlainObject(base) && isPlainObject(overrides)) {
331	    const result: MutableJsonObject = { ...base };
332	    for (const key of Object.keys(overrides)) {
333	      const next = overrides[key];
334	      result[key] =
335	        key in base && next !== undefined
336	          ? deepMerge(base[key] as Json, next)
337	          : (next as Json);
338	    }
339	    return result;
340	  }
341	  return overrides;
342	};
