344	/**
345	 * Set the leaf at a dotted `path` on a structurally-cloned copy of `doc`,
346	 * resolving each segment by **identity** when it descends into an array (ADR
347	 * 0006): a `<slug>` / `<id>` segment selects the array item whose `slug` / `id`
348	 * equals it, never an array index. The image-upload rewrite (`applyImageUpload`)
349	 * targets a key this way (`team.<id>.photo.key`,
350	 * `conferences./2024.speakers.<id>.photo.key`), so a freshly-reordered list never
351	 * rewrites the wrong item's image. A segment that resolves to no array item (or a
352	 * non-container) leaves `doc` untouched — the strict decode downstream is the gate.
353	 */
354	export const setAtPath = (doc: Json, path: string, value: Json): Json => {
355	  const clone = structuredClone(doc) as Json;
356	  return setByIdentity(clone, path.split('.'), value);
357	};
358	
359	/**
360	 * Return a fresh `node` with `value` set at `path`, navigating objects by key
361	 * and arrays by item **identity** (`id` / `slug`). Missing **object** keys along
362	 * the path are created (so an image upload to a freshly-added stub item — which
363	 * carries only its `id`, with no `photo` object yet — still lands its key, just
364	 * as the old positional `setPath` created intermediates). An **array** segment is
365	 * never fabricated: an identity that matches no item leaves `node` unchanged (a
366	 * structural add is `applyListEdit`'s job, never an upload's). Containers along
367	 * the path are cloned, so the input is never mutated.
368	 */
369	const setByIdentity = (
370	  node: Json,
371	  path: readonly string[],
372	  value: Json,
373	): Json => {
374	  const [head, ...rest] = path;
375	  if (head === undefined) return value;
376	  if (Array.isArray(node)) {
377	    let hit = false;
378	    const next = node.map((item) => {
379	      if (hit || itemIdentity(item) !== head) return item;
380	      hit = true;
381	      return setByIdentity(item, rest, value);
382	    });
383	    return hit ? next : node;
384	  }
385	  if (isPlainObject(node)) {
386	    if (rest.length === 0) return { ...node, [head]: value };
387	    const existing: Json | undefined = node[head];
388	    // Descend into an existing container; otherwise create a fresh object so the
389	    // remaining path can be built (an absent or scalar slot is replaced, never
390	    // left to silently drop the write — mirrors the old `setPath`).
391	    const child: Json =
392	      existing !== undefined &&
393	      (isPlainObject(existing) || Array.isArray(existing))
394	        ? existing
395	        : {};
396	    return { ...node, [head]: setByIdentity(child, rest, value) };
397	  }
398	  return node;
399	};

