 62	export const action = routeFormAction(function* () {
 63	  const { url } = yield* ReactRouterContext;
 64	  const submission = yield* SubmissionContext;
 65	  const env = yield* Env.Service;
 66	  if (Option.isNone(env.sendgrid)) {
 67	    return yield* notFound();
 68	  }
 69	  const sendgrid = yield* Sendgrid.Service;
 70	  const toast = yield* Toast;
 71	
 72	  const parsed = parseSchema(schema, submission.payload);
 73	  if (Result.isFailure(parsed)) {
 74	    return yield* formValidationError(formatSchemaResult(parsed) ?? {});
 75	  }
 76	  const data = parsed.success;
 77	
 78	  const result = yield* Effect.exit(sendgrid.subscribe(data.email, data.name));
 79	  if (result._tag === "Failure") {
 80	    yield* Effect.logError("newsletter subscribe failed", result.cause);
 81	    return yield* formValidationError({
 82	      formErrors: ["main.newsletter.error" satisfies TranslationKey],
 83	    });
 84	  }
 85	
 86	  return yield* toast.redirect(url.pathname, {
 87	    type: "success",
 88	    title: "main.newsletter.success.title" satisfies TranslationKey,
 89	    description: "main.newsletter.success.description" satisfies TranslationKey,
 90	    form: "newsletter-form",
 91	  });
 92	});
