 25	/**
 26	 * The `Content` service is the single read path for the public site (C3). These
 27	 * tests pin the behaviour the migrated routes depend on:
 28	 *   - it falls back to the bundled defaults when the bucket has no document, so
 29	 *     dev / a bucket-less prod render exactly like today (D3);
 30	 *   - it decodes a real published document at the boundary and converts it to
 31	 *     the legacy route shape (per-locale strings, `[start, end]` ms tuples,
 32	 *     leading-`/` image URLs) so component code is unchanged;
 33	 *   - the current-conference-by-date and by-year selection match today's
 34	 *     `conference.server.ts` semantics (`derive-dont-sync`);
 35	 *   - reads are cached within the TTL (same reference) and refreshed after it,
 36	 *     concurrent first-reads are single-flighted, and the editor's `bust` makes
 37	 *     a publish visible on the next read (`use-the-platform` — the built-in
 38	 *     `Effect.cachedInvalidateWithTTL`).
 39	 */
 40	
 41	const encode = Schema.encodeUnknownEffect(Schema.fromJsonString(SiteContent));
 42	
 43	/** A `Storage` with no document — every read reports `NotFound` (bucket-less). */
 44	const emptyStorage = Layer.succeed(
 45	  Storage.Service,
 46	  Storage.Service.of({
 47	    get: (key) => Effect.fail(new NotFound({ key })),
 48	    put: (key) =>
 49	      Effect.fail(
 50	        new StorageError({ key, op: 'put', cause: new Error('disabled') }),
 51	      ),
 52	    head: () => Effect.succeed(Option.none()),
 53	    list: () => Effect.succeed([]),
 54	    delete: () => Effect.void,
 55	  }),
 56	);
 57	
 58	/**
 59	 * Provide `Content` (with its `Storage` requirement satisfied) AND expose the
 60	 * SAME built `Storage` to the test effect: `Content.layer` keeps its `Storage`
 61	 * requirement open and is merged with the same `storageLayer` that is also
 62	 * exposed, so both resolve to the one built instance — a `put` from the test hits
 63	 * the same backing store `Content` reads (publish → bust → read).
 64	 *
 65	 * `it.effect` already provides a `Scope` and a `TestClock`, so this helper does
 66	 * neither — it is a pure layer provide.
 67	 */
 68	const provideContent =
 69	  (storageLayer: Layer.Layer<Storage.Service>) =>
 70	  <A, E>(effect: Effect.Effect<A, E, Content.Service | Storage.Service>) =>
 71	    effect.pipe(Effect.provide(Layer.provideMerge(Content.layer, storageLayer)));
 72	
 73	/**
 74	 * Build a `Storage` layer from a `SiteContent` doc encoded to its on-bucket JSON.
 75	 * The encode is an `Effect<string, SchemaError>`, so the layer is built via
 76	 * `Layer.unwrap`; a seed doc that won't encode is a test bug, not a tested
 77	 * failure path, so the `SchemaError` is promoted to a defect (`orDie`) — this
 78	 * keeps the resulting layer's error channel `never`, as `provideContent` requires.
 79	 */
 80	const seededStorage = (
 81	  doc: SiteContentType,
 82	  factory: (json: string) => Layer.Layer<Storage.Service>,
 83	): Layer.Layer<Storage.Service> =>
 84	  Layer.unwrap(encode(doc).pipe(Effect.orDie, Effect.map(factory)));
