 87	 * Provide `Content` over a bucket pre-seeded with a single encoded `SiteContent`
 88	 * document at `content/site.json`. The test body just reads through `Content`,
 89	 * exactly as the public site does.
 90	 */
 91	const provideSeeded = (doc: SiteContentType) =>
 92	  provideContent(
 93	    seededStorage(doc, (json) =>
 94	      layerTest({ [SITE_CONTENT_KEY]: { body: json } }),
 95	    ),
 96	  );
