398	/** The exact override the migrated route hands `editDocument` (content.tsx:183). */
399	const routeOverride = (
400	  entries: ReadonlyArray<readonly [string, string]>,
401	): Json =>
402	  deepMerge(assembleOverrides(entries), {
403	    translations: collectTranslations(entries),
404	  } as Json);
