406	/** The deleted inline algorithm, reproduced verbatim, returning the stored JSON. */
407	const inlineOracle = (
408	  current: SiteContentType,
409	  entries: ReadonlyArray<readonly [string, string]>,
410	) =>
411	  Effect.gen(function* () {
412	    const base = (yield* encodeObject(current)) as Json;
413	    const overrides = assembleOverrides(entries);
414	    const translations = collectTranslations(entries);
415	    const merged = deepMerge(deepMerge(base, overrides), {
416	      translations,
417	    } as Json);
418	    const decoded = yield* decodeMerged(merged);
419	    return yield* encodeObjectJson(decoded);
420	  });
