11	/**
12	 * The `RichText` renderer is the ONLY place page copy becomes markup (the token
13	 * model is closed — text / bold / link — never arbitrary HTML). These render
14	 * tests pin the load-bearing behaviour the FAQ / contact / volunteer migration
15	 * depends on (`prove-it-works`):
16	 *   - a `bold` run renders `<strong class="font-bold">` (matching the old
17	 *     `<span className="font-bold">`),
18	 *   - an `italic` run renders `<span class="italic">` (matching the old FAQ refund
19	 *     footnote `<span className="italic">`),
20	 *   - a `link` run renders an external anchor with the validated href,
21	 *   - a `\n\n` inside a text run renders back as `<br/><br/>` (the legacy
22	 *     paragraph break carried through the token model as data).
23	 */
24	
25	const render = (runs: readonly RichTextRun[]): string =>
26	  renderToStaticMarkup(<RichText runs={runs} />);
27	
28	describe('RichText', () => {
29	  it('renders a plain text run verbatim', () => {
30	    expect(render([{ kind: 'text', value: 'hello world' }])).toBe(
31	      'hello world',
32	    );
33	  });
34	
35	  it('renders a bold run as a bold span', () => {
36	    const html = render([{ kind: 'bold', value: 'BEFORE' }]);
37	    expect(html).toContain('font-bold');
38	    expect(html).toContain('BEFORE');
39	  });
40	
41	  it('renders an italic run as an italic span', () => {
42	    const html = render([{ kind: 'italic', value: 'footnote' }]);
43	    expect(html).toContain('italic');
44	    expect(html).toContain('footnote');
45	  });
46	
47	  it('renders a link run as an external anchor with its href', () => {
48	    const html = render([
49	      { kind: 'link', text: 'hello@gyccanada.org', href: 'mailto:hello@gyccanada.org' },
50	    ]);
51	    expect(html).toContain('href="mailto:hello@gyccanada.org"');
52	    expect(html).toContain('target="_blank"');
53	    expect(html).toContain('hello@gyccanada.org');
54	  });
55	
56	  it('turns a `\\n\\n` inside a text run into a `<br/><br/>` paragraph break', () => {
57	    const html = render([{ kind: 'text', value: 'first\n\nsecond' }]);
58	    expect(html).toContain('first');
59	    expect(html).toContain('second');
60	    expect(html).toContain('<br/><br/>');
61	    // The literal newline characters do NOT leak into the markup.
62	    expect(html).not.toContain('\n\n');
63	  });
64	
65	  it('FAQ refund footnote renders inside an italic span (content -> token -> DOM parity)', () => {
66	    // Closes the loop the 5.4 review flagged: the pre-migration FAQ route rendered the
67	    // refund footnote in `<span className="italic">`. This pipes the real FAQ default
68	    // through the projection + renderer and asserts the footnote text lands inside an
69	    // italic span — not a bare/non-italic run.
70	    const faq = toFaqView(defaultFaqPage, Locale.En);
71	    const refundAnswer = faq.items.find((item) =>
72	      item.answer.some(
73	        (run) => run.kind === 'italic' && run.value.startsWith('* The ONLY'),
74	      ),
75	    )?.answer;
76	    expect(refundAnswer).toBeDefined();
77	
78	    const html = render(refundAnswer ?? []);
79	    const match = html.match(/<span class="italic">([^<]*)<\/span>/);
80	    expect(match?.[1]).toContain('* The ONLY exception');
81	  });
82	
83	  it('renders a full sequence in order', () => {
84	    const html = render([
85	      { kind: 'bold', value: 'BEFORE' },
86	      { kind: 'text', value: ' registering, email ' },
87	      { kind: 'link', text: 'us', href: 'mailto:hello@gyccanada.org' },
88	    ]);
89	    expect(html.indexOf('BEFORE')).toBeLessThan(
90	      html.indexOf('registering'),
91	    );
92	    expect(html.indexOf('registering')).toBeLessThan(html.indexOf('mailto'));
93	  });
94	});

